Perfect! Now I have a comprehensive understanding. Let me create a detailed report for you.

## Comprehensive shadcn/ui Component Library Structure Report

Based on my thorough investigation of the shadcn/ui repository, here's everything you need to know to add a new "Stepper" component:

---

### 1. OVERALL DIRECTORY STRUCTURE

**Main location:** `/apps/v4/` contains the official documentation and component implementation.

Key directories:
- `/apps/v4/registry/new-york-v4/ui/` - All UI component source code (59 components)
- `/apps/v4/registry/new-york-v4/examples/` - Component examples/demos
- `/apps/v4/registry/new-york-v4/hooks/` - Reusable hooks (e.g., `use-mobile.ts`)
- `/apps/v4/registry/new-york-v4/lib/` - Utilities (cn function)
- `/apps/v4/registry/new-york-v4/ui/_registry.ts` - Component registration file
- `/apps/v4/registry/new-york-v4/examples/_registry.ts` - Example registration file

**Build outputs:**
- `/apps/v4/registry.json` - Generated registry JSON for distribution
- `/apps/v4/registry/new-york-v4/registry.ts` - Master registry combining all items

---

### 2. COMPOUND COMPONENT PATTERNS (Accordion, Tabs, Collapsible)

All three use **Radix UI as underlying primitives**. Here's the pattern:

#### **Simple Pattern (Collapsible)** - Minimal wrapping
File: `/apps/v4/registry/new-york-v4/ui/collapsible.tsx`

```typescript
"use client"

import { Collapsible as CollapsiblePrimitive } from "radix-ui"

function Collapsible({
  ...props
}: React.ComponentProps<typeof CollapsiblePrimitive.Root>) {
  return <CollapsiblePrimitive.Root data-slot="collapsible" {...props} />
}

function CollapsibleTrigger({
  ...props
}: React.ComponentProps<typeof CollapsiblePrimitive.CollapsibleTrigger>) {
  return (
    <CollapsiblePrimitive.CollapsibleTrigger
      data-slot="collapsible-trigger"
      {...props}
    />
  )
}

function CollapsibleContent({
  ...props
}: React.ComponentProps<typeof CollapsiblePrimitive.CollapsibleContent>) {
  return (
    <CollapsiblePrimitive.CollapsibleContent
      data-slot="collapsible-content"
      {...props}
    />
  )
}

export { Collapsible, CollapsibleTrigger, CollapsibleContent }
```

**Key patterns:**
- Each sub-component is its own function (no classes)
- All export as named exports
- Use `data-slot="component-name"` for styling hooks
- `"use client"` directive at top for client-side components
- Spread all props with `...props`

#### **Medium Pattern (Accordion)** - With styling and icons
File: `/apps/v4/registry/new-york-v4/ui/accordion.tsx`

```typescript
"use client"

import * as React from "react"
import { ChevronDownIcon } from "lucide-react"
import { Accordion as AccordionPrimitive } from "radix-ui"
import { cn } from "@/lib/utils"

// Root component - minimal
function Accordion({
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

// Item with border styling
function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn("border-b last:border-b-0", className)}
      {...props}
    />
  )
}

// Trigger with icon and complex styling
function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "flex flex-1 items-start justify-between gap-4 rounded-md py-4 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-180",
          className
        )}
        {...props}
      >
        {children}
        <ChevronDownIcon className="..." />
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

// Content with animation
function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="overflow-hidden text-sm data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down"
      {...props}
    >
      <div className={cn("pt-0 pb-4", className)}>{children}</div>
    </AccordionPrimitive.Content>
  )
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }
```

#### **Complex Pattern (Tabs)** - With orientation support
File: `/apps/v4/registry/new-york-v4/ui/tabs.tsx`

```typescript
"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { Tabs as TabsPrimitive } from "radix-ui"
import { cn } from "@/lib/utils"

// Root with orientation
function Tabs({
  className,
  orientation = "horizontal",
  ...props
}: React.ComponentProps<typeof TabsPrimitive.Root>) {
  return (
    <TabsPrimitive.Root
      data-slot="tabs"
      data-orientation={orientation}
      orientation={orientation}
      className={cn(
        "group/tabs flex gap-2 data-[orientation=horizontal]:flex-col",
        className
      )}
      {...props}
    />
  )
}

// Variants with CVA for responsive styling
const tabsListVariants = cva(
  "group/tabs-list inline-flex w-fit items-center justify-center rounded-lg p-[3px] text-muted-foreground group-data-[orientation=horizontal]/tabs:h-9 group-data-[orientation=vertical]/tabs:h-fit group-data-[orientation=vertical]/tabs:flex-col data-[variant=line]:rounded-none",
  {
    variants: {
      variant: {
        default: "bg-muted",
        line: "gap-1 bg-transparent",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

// List using variant system
function TabsList({
  className,
  variant = "default",
  ...props
}: React.ComponentProps<typeof TabsPrimitive.List> &
  VariantProps<typeof tabsListVariants>) {
  return (
    <TabsPrimitive.List
      data-slot="tabs-list"
      data-variant={variant}
      className={cn(tabsListVariants({ variant }), className)}
      {...props}
    />
  )
}

// Export variants for external use
export { Tabs, TabsList, TabsTrigger, TabsContent, tabsListVariants }
```

**Key patterns for compound components:**

1. **Use "use client" directive** at the top if managing any state or events
2. **Wrapper functions for each sub-component** - one function per Radix primitive
3. **Use data-slot attributes** - enables CSS-in-JS styling via `[data-slot]` selectors
4. **data-orientation tracking** - stored on parent, used in child selectors via group modifiers
5. **CVA (class-variance-authority)** for complex styling variants
6. **cn() utility** from clsx + tailwind-merge for combining Tailwind classes
7. **All exports are named exports** at bottom of file
8. **Support className overrides** by accepting and merging with cn()

---

### 3. CONTEXT USAGE FOR STATE SHARING

#### **Pattern: Create Context + Custom Hook** (Sidebar example)
File: `/apps/v4/registry/new-york-v4/ui/sidebar.tsx` (lines 35-54)

```typescript
type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  toggleSidebar: () => void
}

const SidebarContext = React.createContext<SidebarContextProps | null>(null)

function useSidebar() {
  const context = React.useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.")
  }
  return context
}

// In provider component:
const contextValue = React.useMemo<SidebarContextProps>(
  () => ({
    state,
    open,
    setOpen,
    isMobile,
    openMobile,
    setOpenMobile,
    toggleSidebar,
  }),
  [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
)

return (
  <SidebarContext.Provider value={contextValue}>
    {children}
  </SidebarContext.Provider>
)
```

#### **Pattern: FormField Context** (Form example)
File: `/apps/v4/registry/new-york-v4/ui/form.tsx` (lines 24-66)

```typescript
type FormFieldContextValue<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = {
  name: TName
}

const FormFieldContext = React.createContext<FormFieldContextValue>(
  {} as FormFieldContextValue
)

const FormField = <
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
  ...props
}: ControllerProps<TFieldValues, TName>) => {
  return (
    <FormFieldContext.Provider value={{ name: props.name }}>
      <Controller {...props} />
    </FormFieldContext.Provider>
  )
}

const useFormField = () => {
  const fieldContext = React.useContext(FormFieldContext)
  const itemContext = React.useContext(FormItemContext)

  if (!fieldContext) {
    throw new Error("useFormField should be used within <FormField>")
  }

  return { id, name, formItemId, formDescriptionId, formMessageId, ...fieldState }
}
```

**Context patterns:**

1. **Define typed context value** - TypeScript interface for type safety
2. **Create context with default** - `React.createContext<Type>(defaultValue)`
3. **Custom hook for consumption** - wraps `useContext()` with error checking
4. **Memoize context values** - use `React.useMemo()` to prevent unnecessary re-renders
5. **Error boundaries** - throw error in hook if context not available

---

### 4. HOW ORIENTATIONS/VARIANTS ARE HANDLED

#### **Method 1: data-orientation + Group Selectors** (Tabs)
```typescript
// In parent component
<TabsPrimitive.Root
  data-slot="tabs"
  data-orientation={orientation}
  orientation={orientation}
  className={cn(
    "group/tabs flex gap-2 data-[orientation=horizontal]:flex-col",
    className
  )}
  {...props}
/>

// In child component
className={cn(
  "group-data-[orientation=horizontal]/tabs:h-9 group-data-[orientation=vertical]/tabs:h-fit",
  className
)}
```

#### **Method 2: CVA Variants** (Badge, Button)
```typescript
const badgeVariants = cva(
  "inline-flex w-fit shrink-0 items-center justify-center...",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground",
