"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

/* ----- Stepper Context ----- */

type StepperContextValue = {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper>.")
  }
  return context
}

/* ----- Step Item Context ----- */

type StepperItemContextValue = {
  step: number
  state: "active" | "completed" | "inactive"
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem>.")
  }
  return context
}

/* ----- Stepper ----- */

function Stepper({
  value: valueProp,
  onValueChange: onValueChangeProp,
  defaultValue = 1,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  onValueChange?: (value: number) => void
  defaultValue?: number
  orientation?: "horizontal" | "vertical"
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const value = valueProp ?? internalValue
  const onValueChange = React.useCallback(
    (newValue: number) => {
      if (onValueChangeProp) {
        onValueChangeProp(newValue)
      } else {
        setInternalValue(newValue)
      }
    },
    [onValueChangeProp]
  )

  const contextValue = React.useMemo<StepperContextValue>(
    () => ({ value, onValueChange, orientation }),
    [value, onValueChange, orientation]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          "data-[orientation=horizontal]:flex-col",
          "data-[orientation=vertical]:flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

/* ----- StepperItem ----- */

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = useStepper()
  const state =
    step === value ? "active" : step < value ? "completed" : "inactive"

  const contextValue = React.useMemo<StepperItemContextValue>(
    () => ({ step, state }),
    [step, state]
  )

  return (
    <StepperItemContext.Provider value={contextValue}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "group/stepper-item flex items-center gap-3",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

/* ----- StepperTrigger ----- */

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      className={cn(
        "inline-flex items-center gap-3 rounded-md text-left outline-none transition-colors",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(step)}
      {...props}
    >
      {children}
    </button>
  )
}

/* ----- StepperIndicator ----- */

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { state, step } = useStepperItem()

  return (
    <div
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=inactive]:border-muted-foreground/30 data-[state=inactive]:text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : (
          step
        ))}
    </div>
  )
}

/* ----- StepperTitle ----- */

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium",
        "data-[state=active]:text-foreground",
        "data-[state=completed]:text-foreground",
        "data-[state=inactive]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

/* ----- StepperDescription ----- */

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

/* ----- StepperSeparator ----- */

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="separator"
      className={cn(
        "bg-muted-foreground/30",
        "data-[orientation=horizontal]:h-px data-[orientation=horizontal]:flex-1",
        "data-[orientation=vertical]:mx-auto data-[orientation=vertical]:h-auto data-[orientation=vertical]:w-px data-[orientation=vertical]:self-stretch",
        className
      )}
      {...props}
    />
  )
}

/* ----- StepperContent ----- */

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = useStepper()

  if (step !== value) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("flex-1", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
}

