      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

/* ----- StepperSeparator ----- */

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="separator"
      className={cn(
        "bg-muted-foreground/30",
        "data-[orientation=horizontal]:h-px data-[orientation=horizontal]:flex-1",
        "data-[orientation=vertical]:mx-auto data-[orientation=vertical]:h-auto data-[orientation=vertical]:w-px data-[orientation=vertical]:self-stretch",
        className
      )}
      {...props}
    />
  )
}

/* ----- StepperContent ----- */

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = useStepper()

  if (step !== value) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("flex-1", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
}

